"""
MKT Christ — 1 Samuel chapters 19–21
Run: python3 scripts/zc-christ-1samuel-19-21-full.py

Ch19: Saul hunts David; Jonathan intercedes; escape via window; Naioth/Spirit protection (24 verses)
Ch20: Jonathan-David covenant, arrow signal, farewell (42 verses)
Ch21: Nob showbread; Achish/feigned madness; Goliath's sword (15 verses)

Key Christological themes:
- Jonathan as advocate before Saul → Christ as intercessor/advocate before the Father
- Saul's murderous pursuit of the anointed → spiritual powers' opposition to Christ
- Spirit preventing harm to David at Naioth → divine protection of the Son
- Saul involuntarily prophesying → enemies of Christ unwittingly serve YHWH
- Michal lowering David through the window → escape pattern; Paul in Acts 9:25
- Jonathan-David covenant (hesed ʿolam) → new covenant in Christ's blood
- David eating the showbread → Matt 12:3-4: Jesus explicitly cites this episode
- Feigned madness before Achish → hidden wisdom of the incarnate Son
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / f'mkt-{source}' / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / f'mkt-{source}' / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "19": {
    "1": "<p>Saul orders Jonathan and his servants to kill David. The command that the anointed king be put to death by the existing power structure is the pattern fulfilled in the Sanhedrin's decision against Jesus: &#8220;it is better for you that one man die for the people than that the whole nation perish&#8221; (John 11:50). In both cases the established authority perceives the anointed as a threat and issues a death order. Jonathan's refusal to obey the death order parallels those in the passion narrative who resist the crowd's momentum (Pilate's attempts to release Jesus, Nicodemus's protest in John 7:51).</p>",
    "2": "<p>Jonathan warns David — &#8220;be on guard tomorrow morning; stay in a secret place and hide&#8221; — the covenant friend protecting the anointed from the lethal threat. The disciples warning Paul of plots (Acts 9:24; 20:3) and the angel warning Joseph to flee to Egypt (Matt 2:13) follow the same structural pattern of covenant loyalty providing protective intelligence. The one who loves the anointed risks his own position to secure the anointed's survival — Jonathan risks Saul's wrath as the disciples risk the crowd's anger.</p>",
    "3": "<p>Jonathan positions himself as the intermediary between David and Saul — standing near his father in the field to speak on David's behalf. The mediating position — between the threatening authority and the threatened anointed — is the structure of Christ's high priestly intercession: &#8220;he always lives to make intercession for them&#8221; (Heb 7:25). Jonathan places himself between the executioner and the condemned, which is structurally what Christ's death accomplishes: standing between the just condemnation of sinners and the sinners themselves.</p>",
    "4": "<p>Jonathan's defense of David before Saul: &#8220;the king must not wrong his servant David, because he has not wronged you&#8221; — an appeal to the innocence of the accused before the hostile judge. Peter's defense of Jesus before the crowd (Acts 3:13-14: &#8220;you handed over and rejected him in Pilate's presence, even though he decided to release him&#8221;) and Pilate's own repeated declaration (John 18:38; 19:4,6: &#8220;I find no basis for a charge against him&#8221;) establish Jesus's innocence through exactly this courtroom-advocacy pattern that Jonathan models before Saul.</p>",
    "5": "<p>&#8220;He risked his life and struck down the Philistine, and YHWH won a great victory for all Israel.&#8221; Jonathan's appeal rests on David's prior covenant service: the act of self-giving for the nation's sake establishes the claim to covenant protection in return. Christ's argument before the Father rests on his own prior act of self-giving: &#8220;by his own blood he entered once for all into the holy places, having obtained an eternal redemption&#8221; (Heb 9:12). The intercessor whose plea rests on his own sacrificial act on behalf of the ones he intercedes for — this is the structure both Jonathan and Christ embody.</p>",
    "6": "<p>Saul swears an oath: &#8220;As YHWH lives, David shall not be put to death.&#8221; The temporary reconciliation accomplished through Jonathan's advocacy restores David to Saul's presence — but it will not last. Christ's intercession, by contrast, is permanently effective: &#8220;he is able to save to the uttermost those who draw near to God through him, since he always lives to make intercession for them&#8221; (Heb 7:25). Jonathan's successful intercession restores David provisionally; Christ's intercession restores us permanently.</p>",
    "7": "<p>Jonathan calls David and brings him back to Saul; David serves before Saul as before. The restoration of the anointed to the covenant community through the advocate's intervention is the pattern of reconciliation theology. Paul in 2 Cor 5:18-19: &#8220;God was reconciling the world to himself in Christ... not counting their trespasses against them.&#8221; David's return to service before Saul through Jonathan's mediation is the small-scale type of humanity's restoration to service before YHWH through Christ's mediation.</p>",
    "8": "<p>War breaks out again; David fights and routes the Philistines. David's ongoing military service — fighting the nation's enemies while under threat from within his own court — parallels Christ's redemptive work accomplished amid the hostility of those he came to save. The pattern: the anointed's greatest victories for the covenant community occur precisely during the period when the covenant community's leadership is most hostile to him.</p>",
    "9": "<p>A harmful spirit from YHWH came upon Saul as David played the lyre. The recurrence of the evil spirit despite Jonathan's successful intercession marks the structural limitation of human mediation: Jonathan cannot permanently solve what is a spiritual-covenantal problem with Saul's heart. Only the mediator whose intercession is grounded in his own atonement (Christ) achieves permanent reconciliation; the mediator whose intercession is merely verbal (Jonathan) buys time but cannot secure permanent peace.</p>",
    "10": "<p>Saul hurls the spear at David; David dodges and it sticks in the wall. The assassination attempt at close range, in the context of service, is the structure of the betrayal scenario — the deadly attack from the insider position. Judas at the table (Luke 22:21: &#8220;the hand of him who betrays me is with mine on the table&#8221;) and the arrest in Gethsemane represent this same &#8220;attack during service&#8221; pattern. David's escape from the spear is YHWH's preservation of the anointed; Christ's survival until &#8220;his hour had come&#8221; (John 2:4; 7:30; 8:20: they tried to seize him but no one laid a hand on him because his hour had not yet come) is the same divine timing.</p>",
    "11": "<p>Saul sends agents to watch David's house through the night and kill him in the morning. Michal warns David: &#8220;if you don't save yourself tonight, tomorrow you'll be dead.&#8221; The nighttime watch of the anointed's dwelling with intent to kill at dawn is the structural background for the disciples watching in Gethsemane (with the opposite dynamic: the watch fails to protect, and at dawn the arrest occurs). Both involve a nighttime transition from safety to mortal danger for YHWH's anointed.</p>",
    "12": "<p>Michal lowered David through a window, and he fled. The window-escape of the anointed to preserve his life from a lethal authority is the OT pattern that recurs in Acts 9:25 — Paul lowered in a basket through the city wall at Damascus to escape the plot against his life. Both escapes preserve a covenant servant whose mission is not yet complete; both are accomplished through the agency of a protector who risks their own position. The anointed's work must be completed before his life is taken; premature death is prevented by YHWH's providence working through human instruments.</p>",
    "13": "<p>Michal places a household idol in the bed with a goat-hair cushion at the head to deceive the messengers. The image of a sleeping figure used to buy the anointed time is a deception that protects David — similar to the deception of the guards at the tomb (Matt 28:12-15: the priests paid the soldiers to say the disciples stole the body while they slept). In both cases a constructed false narrative of &#8220;presence&#8221; (David apparently sick in bed; Jesus apparently still in the tomb) is used to give the anointed time — one to escape, one to fulfill his resurrection mission before official opposition could organize.</p>",
    "14": "<p>Michal tells the messengers David is ill. The false report delays the execution order. The lie that protects the anointed is Michal's personal risk — she will face Saul's anger for this deception. Christ's disciples risk themselves to protect his mission: Joseph of Arimathea going to Pilate to secure the body (Mark 15:43: &#8220;taking courage&#8221;), Nicodemus bringing spices for burial. The covenant friends who put themselves at risk to serve the anointed at moments of crisis form the supporting cast of both David's and Jesus's story.</p>",
    "15": "<p>Saul's intensified command — &#8220;bring him in his bed, that I may kill him&#8221; — demonstrates how opposition to the anointed escalates when initial attempts fail. The intensification pattern is consistent in the gospels: the Pharisees' initial criticism escalates to plotting (John 11:53: from that day they made plans to put him to death), intensifies further to conspiracy (Matt 26:3-4), and culminates in the trial. The failure to eliminate the anointed at each stage drives the opposition to more extreme measures.</p>",
    "16": "<p>The messengers enter and find only the idol in the bed. The discovery of the empty place where the anointed was expected to be dead is the anti-type of the empty tomb. The women came to the tomb and found it empty (Mark 16:4-6: &#8220;he has risen; he is not here&#8221;); Saul's agents came to David's bed and found only a substitute image. In both cases the anointed is gone when his enemies expected to find him; in both cases the escape confounds and outrages the opposition.</p>",
    "17": "<p>Saul demands: &#8220;Why have you deceived me?&#8221; Michal replies she had no choice — David threatened her life. The pressure exerted by hostile authority on those who protected the anointed is consistent: after the crucifixion, the disciples feared the Jewish leaders (John 20:19: they were gathered with doors locked for fear of the Jews). Those who show covenant loyalty to Christ must often navigate the hostility of powers threatened by his survival and witness.</p>",
    "18": "<p>David flees to Samuel at Ramah and tells him everything Saul has done. The anointed king fleeing to the prophet who anointed him — bringing his full situation and seeking prophetic counsel — is the pattern of retreat to the source of commissioning under pressure. Christ at Gethsemane brings his full situation to the Father in prayer (Luke 22:41-44: &#8220;Father, if you are willing, take this cup from me&#8221;) — the complete openness between the anointed and the one who sent him, even in extremity. Samuel and David together at Naioth is the prophetic community as a sanctuary for the persecuted anointed.</p>",
    "19": "<p>Word reaches Saul: &#8220;David is at Naioth in Ramah.&#8221; The discovery of the anointed's location by hostile intelligence is a recurring pattern. The Magi's information leading Herod to send soldiers to Bethlehem (Matt 2:16), Judas guiding the arrest party to Gethsemane (John 18:2: &#8220;Judas, who betrayed him, also knew the place&#8221;) — in each case informants reveal where the anointed can be found. The difference: David escapes Naioth; Jesus willingly accepts the arrest when his hour arrives.</p>",
    "20": "<p>Saul's messengers arrive at Naioth and the Spirit of God comes upon them; they prophesy instead of arresting David. The Spirit preventing the arrest of the anointed by transforming his would-be captors into involuntary worshipers is the divine protection pattern fulfilled in Jesus's pre-Passion protection. John 7:45-46: the temple officers sent to arrest Jesus return empty-handed — &#8220;no one ever spoke the way this man does.&#8221; The divine authority that surrounded the anointed repeatedly prevented premature arrest until &#8220;the hour had come&#8221; for his voluntary self-giving.</p>",
    "21": "<p>Three successive groups of Saul's messengers come to Naioth; all prophesy; none arrest David. The threefold repetition of failed attempts to capture the anointed — each attempt met with the same divine intervention — establishes the pattern of YHWH's sovereign protection. Acts 2:24 applies this principle to the resurrection: &#8220;it was not possible for him to be held&#8221; by death. The same impossible-to-hold principle governs David's preservation at Naioth — three groups sent, none succeed — and Christ's preservation until his voluntary death.</p>",
    "22": "<p>Saul goes himself to Ramah, inquiring at the great cistern at Sechu. The escalation from sending agents to coming personally — when all other attempts have failed — mirrors the escalation in the Passion narrative: from sending servants to arrest Jesus (Mark 12:2-5), to sending soldiers (John 18:3), to the high priest himself presiding over the interrogation (Mark 14:53). In both cases the hostile authority's final personal investment in eliminating the anointed is the climactic stage of the pursuit.</p>",
    "23": "<p>As Saul walks toward Naioth the Spirit of God comes upon him and he prophesies all the way there, until he reaches Naioth. The king who comes to destroy the anointed is transformed by the Spirit into a prophet glorifying YHWH before he arrives. Paul's Damascus road conversion is the NT counterpart: the one sent to arrest and destroy the followers of Christ is transformed by the Spirit into Christ's most effective apostle before he arrives at his destination. In both cases YHWH converts the chief persecutor through a Spirit-encounter on the way.</p>",
    "24": "<p>Saul strips off his garments and prophesies before Samuel, lying naked all day and all night. The total incapacitation of the king who sought to kill the anointed — stripped, prostrate, prophesying against his own will — is the pattern of the enemies of Christ being overcome not by force but by divine power. Phil 2:10-11: &#8220;at the name of Jesus every knee will bow and every tongue confess that Jesus Christ is Lord.&#8221; Saul's involuntary prostration before Samuel (the prophet of the anointed) is the small-scale type of the eschatological involuntary confession of every enemy of the anointed King.</p>"
  },
  "20": {
    "1": "<p>David flees to Jonathan, asking &#8220;What have I done? What is my wrong? What is my sin before your father?&#8221; — the declaration of innocence from the one pursued without cause. Christ before Pilate: &#8220;What evil has he done?&#8221; (Matt 27:23); Jesus's own declaration &#8220;which of you convicts me of sin?&#8221; (John 8:46). The innocent anointed pursued by hostile authority with no legitimate charge — David to Jonathan, Jesus to the court — establishes the structural injustice that the NT resurrection reverses: the innocent one vindicated by YHWH after unjust condemnation.</p>",
    "2": "<p>Jonathan insists: &#8220;Far from it — you will not die! My father never acts without telling me.&#8221; Jonathan's confident defense of David is based on his belief in his own access to his father's counsel — he assumes he would know if David were truly condemned. The disciples' confidence before the Passion narrative has the same shape: &#8220;Lord, I am ready to go with you both to prison and to death&#8221; (Luke 22:33). In both cases the defender's confidence reflects a partial understanding of the situation — Jonathan doesn't yet know how determined Saul is; Peter doesn't yet know his own weakness.</p>",
    "3": "<p>David swears: &#8220;Your father knows that I have found favor with you.&#8221; David's insight into his own situation — that he is already effectively condemned — is more accurate than Jonathan's. Christ's foreknowledge of his own death is the NT counterpart: &#8220;The Son of Man must be delivered into the hands of men&#8221; (Mark 9:31; Luke 9:44). The anointed's clear-eyed acceptance of the hostility directed at him, against the well-meaning denial of his closest friend, is the pattern of the Passion prediction cycle.</p>",
    "4": "<p>Jonathan: &#8220;Whatever you want me to do, I will do it.&#8221; The total covenant availability of the covenant friend — offering unconditional service — is the posture Christ's disciples are called to embody. John 15:14-15: &#8220;You are my friends if you do what I command you.&#8221; Jonathan's &#8220;whatever you want me to do&#8221; is the model of covenant friendship in which the friend's will is aligned with the anointed's will. The disciples are called into this relationship — not slaves who do not know the master's purpose, but friends who share in it.</p>",
    "5": "<p>David proposes the new moon test: his empty seat will reveal Saul's true intentions. The indirect revelation of hostility through a deliberate absence is a narrative device: the empty seat exposes what is hidden in Saul's heart. Christ's parables similarly use indirect methods to reveal what is hidden — the parable of the tenants (Matt 21:33-44) exposes the religious leaders' intentions in a form they recognize only after it is told (&#8220;they knew he was talking about them,&#8221; v45). The indirect method of truth-disclosure characterizes the wisdom of the anointed in a hostile environment.</p>",
    "6": "<p>The cover story — David went to Bethlehem for a family sacrifice — uses the legitimate religious calendar as protective cover. The observance of legitimate covenant life as the cover under which the anointed moves is a type of the incarnation's hiddenness: the eternal Son concealed in the ordinary rhythms of Jewish family life in Nazareth (Luke 2:51-52) — &#8220;hidden&#8221; from those who had no eyes to see him in the ordinary family from Galilee. Divine authority concealed within completely ordinary human form.</p>",
    "7": "<p>If Saul answers calmly, peace; if he flares up in anger, Jonathan will know Saul has decided to harm David. The diagnostic test that reveals the heart of the hostile party is the pattern Christ uses in multiple contexts: the question about David's son (Matt 22:41-46), the question about tribute to Caesar (Matt 22:17-21), the healing on the Sabbath performed openly while the Pharisees watch (Mark 3:1-6). The anointed uses situations that reveal what is hidden in his opponents' hearts — and uses the revelation to communicate with those who have eyes to see.</p>",
    "8": "<p>&#8220;Show your covenant loyalty (<em>ḥeseḏ</em>) to your servant — you yourself brought me into a covenant before YHWH.&#8221; The appeal to prior covenant as the basis for present faithfulness is the logic of Christ's intercessory prayer: &#8220;I have given them the words you gave me&#8221; (John 17:8); &#8220;they were yours; you gave them to me&#8221; (17:6). The covenant already made grounds the request for continued faithfulness. David appeals to the covenant Jonathan initiated; believers appeal to the covenant Christ ratified — the basis for confidence in continued covenant protection.</p>",
    "9": "<p>Jonathan: &#8220;If I knew my father had decided to harm you, I would warn you.&#8221; Jonathan's insistence on complete disclosure to David — sharing everything relevant to David's survival — is the model of the friend who withholds nothing. John 15:15: &#8220;I have called you friends, because everything I have heard from my Father I have made known to you.&#8221; Jesus's complete disclosure of the Father's purposes to his disciples is the fulfillment of what Jonathan pledges to David: the anointed's closest companion withholds nothing that affects the other's wellbeing.</p>",
    "10": "<p>David asks: &#8220;Who will let me know if your father answers you harshly?&#8221; — the practical problem of intelligence and communication across distance and danger. The anointed's need for reliable communication from his covenant friend despite the hostile intermediary environment is the structure of the Spirit's role in the church: &#8220;when the Spirit of truth comes, he will guide you into all truth... he will tell you what is to come&#8221; (John 16:13). The arrow-signal system Jonathan devises is a covenant communication network operating beneath the surface of a hostile environment.</p>",
    "11": "<p>&#8220;Come, let's go out to the field&#8221; — the movement from the potentially observed indoor space to the private open field for the covenant oath. Private sacred space for covenant communication between the anointed and his covenant partner is consistent throughout the biblical narrative: Sinai (Moses and YHWH alone), the Mount of Transfiguration (Jesus with three disciples, away from the crowd), Gethsemane (Jesus withdrawing from the disciples to pray). The covenant friend takes the anointed aside for the most intimate communication.</p>",
    "12": "<p>Jonathan's oath: &#8220;By YHWH, the God of Israel — when I sound out my father tomorrow... and the news is good for David, will I not then send to you and disclose it?&#8221; The sworn covenant communication network — Jonathan as reliable intermediary between David's situation and YHWH's protection — is the pattern of the Spirit as the reliable intermediary between the Father's purposes and the church. John 16:14-15: &#8220;He will glorify me, because he will take from what is mine and declare it to you. Everything the Father has is mine; that is why I said the Spirit will take from what is mine and declare it to you.&#8221;</p>",
    "13": "<p>Jonathan invokes YHWH's punishment on himself if he fails to warn David when Saul means harm. The self-imprecation oath — placing oneself under divine sanction to guarantee faithfulness — is the highest level of covenant commitment. Christ's covenant commitment to his people has no conditional element or self-imprecation because his faithfulness is absolute: &#8220;if we are faithless, he remains faithful, for he cannot deny himself&#8221; (2 Tim 2:13). Jonathan's oath is the human approximation of the divine faithfulness that only Christ fully embodies.</p>",
    "14": "<p>&#8220;If I am still alive, show me the steadfast love (<em>ḥeseḏ</em>) of YHWH — do not let me die.&#8221; Jonathan's vulnerability — asking for the protection of YHWH's covenant love through David — is the acknowledgment that his own fate is bound up with David's victory. The church's asking Christ for the <em>ḥeseḏ</em> of the new covenant — &#8220;your steadfast love is before my eyes, and I walk in your faithfulness&#8221; (Ps 26:3) — rests on the same logic: if the anointed is victorious, those in covenant with him share the victory. Jonathan's request anticipates Paul's &#8220;if God is for us, who can be against us?&#8221; (Rom 8:31).</p>",
    "15": "<p>&#8220;Never cut off your steadfast love from my house, even when YHWH has cut off all of David's enemies from the face of the earth.&#8221; The covenant made across the dimension of David's future victory is the structure of the new covenant: the benefits of Christ's finished work applied retroactively and prospectively — to those before and after his coming who are in covenant with him. Jonathan secures covenant protection for his descendants from the future victorious king. Christ's new covenant blood secures eternal redemption for those in covenant with him, reaching backward to Abraham (Gal 3:14) and forward to the consummation.</p>",
    "16": "<p>Jonathan makes a covenant with the house of David, invoking YHWH's judgment on David's enemies. The covenant between Jonathan's house and David's house — solemnized by the mutual enemy-imprecation — is the bilateral covenant structure. The new covenant is the supreme covenant in which YHWH himself is both parties (Gen 15: YHWH alone passes between the pieces) — making it unilaterally secure in a way no bilateral covenant can be. Jonathan's covenant with David requires David's faithfulness; Christ's covenant with his people is grounded in Christ's own faithfulness on both sides.</p>",
    "17": "<p>Jonathan made David swear again because of his love for David, for he loved him as his own soul (<em>kĕnapšô</em>). This is the covenant love that makes Jonathan's commitment absolute: he loves David as himself. This is the Christological love: &#8220;having loved his own who were in the world, he loved them to the end&#8221; (John 13:1); &#8220;Greater love has no one than this: to lay down one's life for one's friends&#8221; (John 15:13). Jonathan's love for David as his own soul is the human approximation of Christ's love for his covenant people — the love that gives everything including life itself.</p>",
    "18": "<p>&#8220;Tomorrow is the new moon feast, and your absence will be noticed — your seat will be empty.&#8221; The empty seat at the covenant feast reveals the anointed's absence and forces the hostile party's hand. The Lord's table in the new covenant is the feast at which the anointed's presence is proclaimed until he comes: &#8220;whenever you eat this bread and drink this cup, you proclaim the Lord's death until he comes&#8221; (1 Cor 11:26). The present feast is both absence (awaiting his return) and presence (he is with us wherever two or three gather in his name, Matt 18:20).</p>",
    "19": "<p>&#8220;On the third day go quickly to the place where you hid when this trouble started, and stay beside the stone Ezel.&#8221; The third day as the appointed time for the decisive revelation of the anointed's situation — whether he is safe or in mortal danger — resonates with the resurrection pattern. &#8220;On the third day he will rise again&#8221; (Matt 20:19) is the NT application of the third-day resurrection structure that runs through the OT (Hos 6:2: &#8220;after two days he will revive us; on the third day he will raise us up&#8221;; Gen 22:4; Jonah 1:17). The third day as the day of decisive divine action is embedded in both David's story and the resurrection.</p>",
    "20": "<p>&#8220;I will shoot three arrows to the side of it, as if I were shooting at a target.&#8221; The arrow-shooting as coded communication system — a message that appears to be practice but carries life-or-death information — is the structure of parabolic communication. Jesus speaks in parables so that &#8220;seeing they do not see, and hearing they do not hear, nor do they understand&#8221; (Matt 13:13) — the message's meaning is veiled for the hostile audience while transparent to those with &#8220;ears to hear.&#8221; Jonathan's arrow-system communicates safely across hostile territory; Christ's parabolic speech communicates across the hostile territory of hardened hearts.</p>",
    "21": "<p>&#8220;If I call to him, &#8216;The arrows are on this side of you, pick them up&#8217; — then come, for YHWH says it is safe for you.&#8221; The coded &#8220;come&#8221; versus &#8220;go&#8221; signal embedded in the arrow-retrieval instruction is covenant intelligence delivered through a seemingly innocent activity. The angels' &#8220;come&#8221; to the women at the empty tomb (&#8220;he has risen from the dead; he is going ahead of you into Galilee; there you will see him&#8221;, Matt 28:7) is the post-resurrection &#8220;it is safe to come out&#8221; signal — the threat is past, the anointed is free, the disciples can emerge from their locked room.</p>",
    "22": "<p>&#8220;If I say to the boy, &#8216;The arrows are farther out&#8217; — then go, for YHWH has sent you away.&#8221; The divine authorization embedded in the &#8220;go&#8221; signal — &#8220;YHWH has sent you away&#8221; — frames even the tactical escape as covenant commission. Christ's post-resurrection commissioning uses the same frame: &#8220;All authority in heaven and on earth has been given to me. Therefore go&#8221; (Matt 28:18-19). The &#8220;go&#8221; that seems like flight is actually divine sending; the apparent retreat is covenant advance. David going from Saul's court into the wilderness is YHWH sending him to his next stage of preparation.</p>",
    "23": "<p>&#8220;As for everything we have agreed on between us — YHWH is witness between you and me forever.&#8221; The covenant ratified with YHWH as eternal witness is the highest possible covenant guarantee. The new covenant sealed with Christ's blood (Luke 22:20: &#8220;this cup that is poured out for you is the new covenant in my blood&#8221;) has YHWH not merely as witness but as the covenant-maker who guarantees his own faithfulness. &#8220;Forever&#8221; (<em>ʿaḏ ʿôlām</em>) in Jonathan's covenant becomes &#8220;eternal&#8221; (<em>aiōnion</em>) in the new covenant: &#8220;the God of peace who brought again from the dead our Lord Jesus... by the blood of the eternal covenant&#8221; (Heb 13:20).</p>",
    "24": "<p>David hides in the field; the new moon comes; the king sits to eat. The feast proceeds without the anointed — the covenant community's gathering in the absence of the one around whom the feast should be organized is the structure of the pre-Parousia church. Paul to the Corinthians: &#8220;you proclaim the Lord's death until he comes&#8221; (1 Cor 11:26) — the supper is eaten in the anointed's absence, pointing toward his return. Saul's feast without David is the distorted version; the church's table fellowship in Christ's name is the redeemed version of the same structure.</p>",
    "25": "<p>The seating arrangement around the table — Saul against the wall, Jonathan opposite, Abner at Saul's side, David's place empty — is a narrative snapshot of the court from which the anointed has been excluded. The Last Supper's table arrangement — Jesus in the center, the twelve around him, the betrayer physically present but spiritually absent — is the inverse: the anointed at the center of his covenant community, with the one who will hand him over occupying the empty-seat role.</p>",
    "26": "<p>Saul says nothing on the first day, assuming David is ceremonially unclean. The charitable interpretation extended to the absent one reflects the new moon feast's religious framework — absence might have a legitimate ritual explanation. The grace of interpreting absence charitably before moving to hostile conclusions is the structure of Christian love: &#8220;love bears all things, believes all things, hopes all things, endures all things&#8221; (1 Cor 13:7). Saul's temporary charity will expire by the second day; covenant love's charity is permanent.</p>",
    "27": "<p>On the second day Saul asks Jonathan: &#8220;Why hasn't Jesse's son come to the meal either yesterday or today?&#8221; The demotion from &#8220;David&#8221; to &#8220;Jesse's son&#8221; marks the shift from pretended neutrality to open contempt. The social derogation of the anointed — stripping his name and replacing it with a dismissive identification — is the linguistic equivalent of Pilate's placard: &#8220;Jesus of Nazareth, the King of the Jews&#8221; (John 19:19) — intended as mockery, it accidentally proclaims the truth. The enemies' contemptuous labels for the anointed often contain more theological accuracy than they intend.</p>",
    "28": "<p>Jonathan relays David's cover story: David asked permission to attend his family's sacrifice at Bethlehem. Jonathan acts as intermediary, carrying David's message to the hostile king — the covenant friend as spokesperson for the absent anointed. The Holy Spirit as the Paraclete performs this mediating function for the absent Christ: &#8220;he will testify about me&#8221; (John 15:26); &#8220;he will take what is mine and declare it to you&#8221; (John 16:14). Jonathan speaks for David before the court that condemned him; the Spirit speaks for Christ before the world that rejected him.</p>",
    "29": "<p>&#8220;Our family has a sacrifice in the city and my brother insisted I be there.&#8221; The family's call preceding the king's summons — a legitimate religious obligation given priority over royal attendance — is the pattern of Acts 5:29: &#8220;we must obey God rather than men.&#8221; The disciples, like David, claim a higher obligation that supersedes the hostile authority's demands. The cover story David uses contains a genuine theological priority even if the specific circumstances are fabricated: covenant family obligations genuinely do take precedence over hostile political demands.</p>",
    "30": "<p>Saul erupts in fury at Jonathan, calling him son of a &#8220;perverse and rebellious woman.&#8221; The abuse directed at the advocate for the anointed — when direct attack on the anointed himself is not possible — is the consistent pattern. When the crowd cannot reach Jesus directly, they abuse his disciples (John 15:18-21: &#8220;if they persecuted me, they will also persecute you&#8221;). The hostility generated by the anointed's presence overflows onto his closest covenant partner when the anointed is out of reach.</p>",
    "31": "<p>&#8220;For as long as Jesse's son lives on this earth, neither you nor your kingdom will stand.&#8221; Saul's recognition that David's survival means the end of his own dynasty is an accurate theological reading of the situation — Saul understands the zero-sum nature of the kingship claim. But his zero-sum logic is wrong: David's reign does not destroy Jonathan but makes his descendants blessed through the covenant (2 Sam 9: Mephibosheth at David's table). Christ's kingdom is similarly understood as a zero-sum threat by those who oppose it — &#8220;if we let him go on like this, everyone will believe in him&#8221; (John 11:48) — but his reign exalts rather than eliminates those who receive him.</p>",
    "32": "<p>Jonathan challenges his father: &#8220;Why should he die? What has he done?&#8221; — the advocate's direct defense before the hostile judge. Pilate's &#8220;I find no fault in him&#8221; (John 18:38; 19:4, 6) is the secular authority echoing the same defense. Jonathan's question (what crime justifies death?) and Pilate's declaration (no crime found) both establish the structural injustice of the proceedings against the anointed. Both advocates ultimately fail to prevent the condemnation — Jonathan is silenced by Saul's spear; Pilate is silenced by the crowd's demand.</p>",
    "33": "<p>Saul hurls his spear at Jonathan. The father's violence against his own son for defending the anointed is the pattern of apostolic suffering: &#8220;A person's enemies will be members of his own household&#8221; (Matt 10:36, quoting Mic 7:6); &#8220;Brother will betray brother to death, and a father his child&#8221; (Matt 10:21). The defense of the anointed ruptures family bonds and brings violence from the closest quarters. Jonathan now knows by personal experience what David told him: Saul is fully determined to eliminate the anointed.</p>",
    "34": "<p>Jonathan rises from the table furious and eats nothing, grieving for David and for his own humiliation. The grief of the covenant friend who has been personally struck for defending the anointed is the pattern of apostolic suffering. The disciples &#8220;left with great sorrow&#8221; (Matt 26:22) when Jesus announced one of them would betray him. Jonathan's table-departure in grief mirrors the disciples' departure from the Last Supper into the night of Gethsemane — the feast that should have been joy becomes the occasion of grief because of the hostile powers that surround the anointed.</p>",
    "35": "<p>Jonathan goes out to the field at the appointed time with the young servant. The covenant communication system is now in operation — the private signal that will tell David whether to stay or flee. The Spirit's timing in directing the apostolic mission follows the same &#8220;appointed time&#8221; structure: Acts 16:6-10 (the Spirit prevents Paul from going to Asia and Bithynia, then directs him to Macedonia through the vision) — the covenant communication network operates according to divine timing, using indirect means to direct the anointed's mission across hostile territory.</p>",
    "36": "<p>Jonathan shoots the arrow that flies beyond the boy. The arrow going &#8220;farther out&#8221; carries the message: go, YHWH has sent you away. The &#8220;go&#8221; signal delivered through an apparently ordinary archery practice is the pattern of divine commissioning hidden in ordinary events. Christ's post-resurrection commissioning is similarly delivered through ordinary meals (the Emmaus road), a beach breakfast (John 21), and an ordinary hillside gathering (Matt 28:16) — the great commission embedded in scenes that look unremarkable from the outside.</p>",
    "37": "<p>Jonathan calls out: &#8220;The arrow is farther out!&#8221; — the coded signal that carries the covenant intelligence. Hidden speech that carries covenant meaning in a hostile environment is the pattern of Christ's teaching in parables: the meaning accessible to disciples, opaque to opponents. &#8220;To you it has been given to know the secrets of the kingdom of heaven, but to them it has not been given&#8221; (Matt 13:11). The arrow's message — &#8220;go&#8221; — is the same message Christ communicates to his disciples through the Spirit after the resurrection: &#8220;go into all the world&#8221; (Mark 16:15).</p>",
    "38": "<p>Jonathan calls &#8220;Hurry! Don't stop!&#8221; The urgency of the covenant commissioning — once the signal is given, swift action is required — mirrors the urgency of the apostolic mission. &#8220;I must work the works of him who sent me while it is day; night is coming when no one can work&#8221; (John 9:4). The anointed's mission has a timeline; the covenant friend's urgent &#8220;don't stop&#8221; is the Spirit's &#8220;the harvest is plentiful but the workers are few&#8221; (Matt 9:37) — urgency proportionate to the stakes.</p>",
    "39": "<p>The boy knew nothing of the meaning; only Jonathan and David understood the signal. The private covenant language accessible only to those who share the covenant — opaque to the uninitiated observer — is the structure of the Spirit's illumination of Scripture and of Christ's teaching. &#8220;The person without the Spirit does not accept the things that come from the Spirit of God... but the person with the Spirit can evaluate all things&#8221; (1 Cor 2:14-15). The servant is present but comprehends nothing; Jonathan and David share the same knowledge because they share the same covenant.</p>",
    "40": "<p>Jonathan hands his weapons to the servant and sends him back to the city. The weapons — the instruments of the signal — are passed on to be carried into ordinary life, while the covenant encounter between Jonathan and David happens privately. The instruments of covenant communication (Scripture, the sacraments) are available to all; the covenant meeting they enable is personal and direct. The boy carries the weapons without knowing their significance; the church carries the forms of covenant communication whose full significance only the Spirit illuminates.</p>",
    "41": "<p>As soon as the boy is gone, David comes out from beside the mound, falls on his face and bows three times; they weep together, David most of all. The covenant farewell with mutual weeping — David most of all — is the intensity of covenant love at the moment of separation. The disciples' grief at the Last Supper (John 16:6: &#8220;because I have said these things to you, sorrow has filled your heart&#8221;) mirrors this — the covenant community weeping at the prospect of separation from the anointed. The tears are proportionate to the love; David weeping most is the anointed's grief at separation from his covenant partner.</p>",
    "42": "<p>&#8220;Go in peace — we have both sworn in YHWH's name: YHWH shall be between you and me, and between your offspring and my offspring, forever.&#8221; Jonathan's farewell is a benediction that extends the covenant across generations into eternity. The &#8220;go in peace&#8221; (<em>lēḵ lĕšālôm</em>) is the priestly blessing released over the departing one. Christ's farewell to his disciples: &#8220;Peace I leave with you; my peace I give to you&#8221; (John 14:27); &#8220;As the Father has sent me, I am sending you&#8221; (John 20:21). The covenant farewell of both Jonathan and Christ releases the covenant partner into mission with the peace of the covenant attending them.</p>"
  },
  "21": {
    "1": "<p>David comes to Nob and Ahimelech the priest meets him trembling, asking why he comes alone. The anointed king arriving at the sanctuary in flight — without his usual attendants, in conditions that suggest crisis — is the pattern of Christ's arrival at the Father's house in the temple (John 2:13-17: he arrived and acted without the usual religious escort). Both arrivals at the sanctuary surprise the official custodians. Ahimelech's trembling at an irregular visit echoes the trembling of the religious authorities at Jesus's provocative presence in the temple.</p>",
    "2": "<p>David's deceptive cover story — sent by the king on a confidential mission, cannot reveal the details — is a lie that enables the anointed's survival. The moral complexity here is real: the NT never directly addresses this episode, though Jesus uses it in a way that validates the action's outcome. The hiddenness of Christ's true identity from the authorities who would destroy him (he could not walk openly in Judea because the Jews were seeking to kill him, John 7:1) involves a strategic withholding of his full identity in certain contexts — not deception, but discretion about the fullness of revelation until the appointed time.</p>",
    "3": "<p>David asks for five loaves or whatever is available. The urgency of the need — no food, no weapons, no attendants — has brought the anointed to depend entirely on what the sanctuary can provide. Christ's dependence on others' provision during his ministry (Luke 8:3: women who supported him out of their means; John 4:8: disciples gone to buy food) is the incarnation's structural dependence — the one who owns everything receives provision from those he has given everything. The anointed in need at the sanctuary is the pattern of the incarnate Son's genuine dependence.</p>",
    "4": "<p>Ahimelech offers the showbread — the bread of the Presence (<em>leḥem happānîm</em>), the twelve loaves consecrated before YHWH and replaced each Sabbath — with the condition that the men have kept themselves from women. Jesus cites this exact episode when the Pharisees challenge the disciples for plucking grain on the Sabbath: &#8220;Have you not read what David did when he was hungry, and those who were with him — how he entered the house of God and ate the bread of the Presence, which it was not lawful for him to eat?&#8221; (Matt 12:3-4; Mark 2:25-26; Luke 6:3-4). Jesus identifies himself with David, his disciples with David's men, and the Sabbath controversy with the showbread controversy: the anointed's needs take priority over ritual law.</p>",
    "5": "<p>David's assurance that his men have kept themselves ritually pure invokes the military purity laws. The sacred bread given to men who are genuinely dedicated to the holy cause — even if the specific ritual form is irregular — is the principle Jesus extracts from this episode: &#8220;the Sabbath was made for man, not man for the Sabbath. So the Son of Man is lord even of the Sabbath&#8221; (Mark 2:27-28). The anointed is not bound by ritual regulations that were made to serve him; he is their lord and their purpose. David eating the showbread and Jesus eating on the Sabbath are both demonstrations of the anointed's authority over the religious law.</p>",
    "6": "<p>The priest gives David the sacred bread — the bread that had been before YHWH, replaced that day with fresh loaves. Sacred bread given from the presence of YHWH to the hungry anointed and his men is a type of the eucharist: the bread from the sanctuary, the bread of the divine Presence, distributed by the priest to those who have been consecrated for the anointed's service. The feeding of the anointed and his community with bread from the Lord's table is the pattern that the Lord's Supper enacts: &#8220;the bread that we break, is it not a participation in the body of Christ?&#8221; (1 Cor 10:16).</p>",
    "7": "<p>Doeg the Edomite — Saul's chief herdsman, detained before YHWH — was present. This detail is inserted because Doeg will later betray this encounter to Saul, triggering the massacre of Nob's priests (ch22). The presence of the traitor at the moment of the anointed's vulnerability is a pattern: Judas is at the Last Supper when Jesus distributes the bread (John 13:26-27); a man is in the crowd who will betray the showbread encounter. The traitor is present at the sacred meal, and his presence will lead to the destruction of those who served the anointed.</p>",
    "8": "<p>David asks if there is a spear or sword available — he came without weapons because &#8220;the king's errand was urgent.&#8221; The anointed king without weapons, dependent on what the sanctuary provides, will receive the sword of the enemy he already defeated. Christ comes to earth without the sword (Matt 26:52: &#8220;put your sword back in its place&#8221;) — the kingdom he establishes does not advance by the sword but by the word and the cross. The anointed's dependence on provision from beyond himself rather than self-sufficient armed power is consistent from David's dependence at Nob to Christ's crucifixion without self-defense.</p>",
    "9": "<p>The priest: &#8220;The sword of Goliath the Philistine — the one you struck down in the Valley of Elah — it is wrapped in a cloth behind the ephod. Take it if you want.&#8221; David's own earlier victory is preserved at the sanctuary and returned to him in his crisis. The decisive victory that had seemed to belong to the past is still available — it has been kept for this moment. Christ's resurrection is the definitive victory over death (1 Cor 15:55-57) kept in reserve and applied in every subsequent crisis of his people: &#8220;where, O death, is your victory? where, O death, is your sting?&#8221; The sword of the old victory equips the anointed for the new crisis.</p>",
    "10": "<p>David flees from Saul and goes to Achish king of Gath — the Philistine king, ruler of Goliath's city. The anointed seeking refuge among the enemies of Israel — the very enemies he has spent his military career defeating — is the extreme of the exile pattern. Christ's exile in Egypt as an infant (Matt 2:14-15) fulfills Hos 11:1: &#8220;Out of Egypt I called my son&#8221; — the Messiah's survival required refuge among Egypt, another historical enemy of Israel. The anointed in the land of his enemies, preserved by YHWH's hand even there, is the pattern of divine sovereignty over hostile territory.</p>",
    "11": "<p>Achish's servants identify David: &#8220;Isn't this David, king of the land? Isn't this the one they sing about — &#8216;Saul has struck down his thousands, and David his ten thousands&#8217;?&#8221; The Philistines identify David as the king of the land before his own people have fully acknowledged it; the foreign servants apply the royal title that Saul refuses to acknowledge. Pilate's placard &#8220;King of the Jews&#8221; (John 19:19) and the Roman soldiers' &#8220;Hail, King of the Jews!&#8221; (Matt 27:29) are the same ironic pattern: foreigners acknowledge the anointed's true identity while the covenant people's leaders deny it.</p>",
    "12": "<p>David was very afraid of Achish king of Gath. The fear is genuine: the man who killed ten thousands of Philistines is now at the mercy of a Philistine king. The vulnerability of the anointed in enemy territory — genuinely endangered — mirrors Christ's genuine vulnerability in the hands of Roman power. The incarnation's condescension involves real vulnerability: Christ was &#8220;made perfect through suffering&#8221; (Heb 2:10) and &#8220;learned obedience through what he suffered&#8221; (Heb 5:8). The anointed's fear is not weakness but the cost of the complete identification with human vulnerability that the redemptive mission requires.</p>",
    "13": "<p>David feigns madness — acting insane, making marks on the gateposts, letting saliva run down his beard. The wise man playing the fool to escape from those who would destroy him is the pattern of the incarnation's kenosis: &#8220;though he was in the form of God, he did not count equality with God a thing to be grasped, but emptied himself, taking the form of a servant&#8221; (Phil 2:6-7). Christ concealing his divine glory in the &#8220;weakness&#8221; of flesh confounds the powers: &#8220;None of the rulers of this age understood this, for if they had, they would not have crucified the Lord of glory&#8221; (1 Cor 2:8). The hidden wisdom looks like folly.</p>",
    "14": "<p>Achish dismisses David: &#8220;This man is obviously mad! Why did you bring him to me?&#8221; The strategy works — the anointed is dismissed as harmless by the hostile king who does not perceive the truth beneath the appearance. &#8220;The message of the cross is foolishness to those who are perishing, but to us who are being saved it is the power of God&#8221; (1 Cor 1:18). The world dismisses the anointed as mad or irrelevant — the carpenter from Galilee, the one who was crucified — and in doing so releases him to accomplish the salvation that the world's hostility cannot prevent.</p>",
    "15": "<p>Achish: &#8220;Do I need madmen, that you've brought this one to carry on in front of me? Is this man supposed to come into my house?&#8221; The hostile king's rejection of the one he perceives as a madman is the world's rejection of the gospel's apparent foolishness. &#8220;God chose what is foolish in the world to shame the wise&#8221; (1 Cor 1:27). The anointed dismissed as a madman and expelled from the enemy's court is protected by the enemy's own contempt — Achish's dismissal saves David's life. God's &#8220;foolish&#8221; strategy of the cross is vindicated precisely by the world's contempt for it; the rejected one becomes the cornerstone.</p>"
  }
}

def main():
    c = load_comm('christ', '1samuel')
    merge_comm(c, CHRIST)
    save_comm('christ', '1samuel', c)
    total = sum(len(v) for v in CHRIST.values())
    print(f'1samuel mkt-christ: wrote {total} verses across ch 19-21')

if __name__ == '__main__':
    main()
